    23→)
    24→
    25→// watchBatchMaxRevs is the maximum distinct revisions that
    26→// may be sent to an unsynced watcher at a time. Declared as
    27→// var instead of const for testing purposes.
    28→var watchBatchMaxRevs = 1000
    29→
    30→type eventBatch struct {
    31→	// evs is a batch of revision-ordered events
    32→	evs []mvccpb.Event
    33→	// revs is the minimum unique revisions observed for this batch
    34→	revs int
    35→	// moreRev is first revision with more events following this batch
    36→	moreRev int64
    37→}
    38→
    39→func (eb *eventBatch) add(ev mvccpb.Event) {
    40→	if eb.revs > watchBatchMaxRevs {
    41→		// maxed out batch size
    42→		return
    43→	}
    44→
    45→	if len(eb.evs) == 0 {
    46→		// base case
    47→		eb.revs = 1
    48→		eb.evs = append(eb.evs, ev)
    49→		return
    50→	}
    51→
    52→	// revision accounting
    53→	ebRev := eb.evs[len(eb.evs)-1].Kv.ModRevision
    54→	evRev := ev.Kv.ModRevision
    55→	if evRev > ebRev {
    56→		eb.revs++
    57→		if eb.revs > watchBatchMaxRevs {
    58→			eb.moreRev = evRev
    59→			return
    60→		}
    61→	}
    62→
    63→	eb.evs = append(eb.evs, ev)
    64→}
    65→
    66→type watcherBatch map[*watcher]*eventBatch
    67→
    68→func (wb watcherBatch) add(w *watcher, ev mvccpb.Event) {
    69→	eb := wb[w]
    70→	if eb == nil {
    71→		eb = &eventBatch{}
    72→		wb[w] = eb
    73→	}
    74→	eb.add(ev)
    75→}
    76→
    77→// newWatcherBatch maps watchers to their matched events. It enables quick
    78→// events look up by watcher.
    79→func newWatcherBatch(wg *watcherGroup, evs []mvccpb.Event) watcherBatch {
    80→	if len(wg.watchers) == 0 {
    81→		return nil
    82→	}
    83→
    84→	wb := make(watcherBatch)
    85→	for _, ev := range evs {
    86→		for w := range wg.watcherSetByKey(string(ev.Kv.Key)) {
    87→			if ev.Kv.ModRevision >= w.minRev {
    88→				// don't double notify
    89→				wb.add(w, ev)
    90→			}
    91→		}
    92→	}
    93→	return wb
    94→}
    95→
    96→type watcherSet map[*watcher]struct{}
    97→
    98→func (w watcherSet) add(wa *watcher) {
    99→	if _, ok := w[wa]; ok {
   100→		panic("add watcher twice!")
   101→	}
   102→	w[wa] = struct{}{}
   103→}
   104→
   105→func (w watcherSet) union(ws watcherSet) {
   106→	for wa := range ws {
   107→		w.add(wa)
   108→	}
   109→}
   110→
   111→func (w watcherSet) delete(wa *watcher) {
   112→	if _, ok := w[wa]; !ok {
   113→		panic("removing missing watcher!")
   114→	}
   115→	delete(w, wa)
   116→}
   117→
   118→type watcherSetByKey map[string]watcherSet
   119→
   120→func (w watcherSetByKey) add(wa *watcher) {
   121→	set := w[string(wa.key)]
   122→	if set == nil {
   123→		set = make(watcherSet)
   124→		w[string(wa.key)] = set
   125→	}
   126→	set.add(wa)
   127→}
   128→
   129→func (w watcherSetByKey) delete(wa *watcher) bool {
   130→	k := string(wa.key)
   131→	if v, ok := w[k]; ok {
   132→		if _, ok := v[wa]; ok {
   133→			delete(v, wa)
   134→			if len(v) == 0 {
   135→				// remove the set; nothing left
   136→				delete(w, k)
   137→			}
   138→			return true
   139→		}
   140→	}
   141→	return false
   142→}
   143→
   144→// watcherGroup is a collection of watchers organized by their ranges
   145→type watcherGroup struct {
   146→	// keyWatchers has the watchers that watch on a single key
   147→	keyWatchers watcherSetByKey
   148→	// ranges has the watchers that watch a range; it is sorted by interval
   149→	ranges adt.IntervalTree
   150→	// watchers is the set of all watchers
   151→	watchers watcherSet
   152→}
   153→
   154→func newWatcherGroup() watcherGroup {
   155→	return watcherGroup{
   156→		keyWatchers: make(watcherSetByKey),
   157→		ranges:      adt.NewIntervalTree(),
   158→		watchers:    make(watcherSet),
   159→	}
   160→}
   161→
   162→// add puts a watcher in the group.
   163→func (wg *watcherGroup) add(wa *watcher) {
   164→	wg.watchers.add(wa)
   165→	if wa.end == nil {
   166→		wg.keyWatchers.add(wa)
   167→		return
   168→	}
   169→
   170→	// interval already registered?
   171→	ivl := adt.NewStringAffineInterval(string(wa.key), string(wa.end))
   172→	if iv := wg.ranges.Find(ivl); iv != nil {
   173→		iv.Val.(watcherSet).add(wa)
   174→		return
   175→	}
   176→
   177→	// not registered, put in interval tree
   178→	ws := make(watcherSet)
   179→	ws.add(wa)
   180→	wg.ranges.Insert(ivl, ws)
   181→}
   182→
   183→// contains is whether the given key has a watcher in the group.
   184→func (wg *watcherGroup) contains(key string) bool {
   185→	_, ok := wg.keyWatchers[key]
   186→	return ok || wg.ranges.Intersects(adt.NewStringAffinePoint(key))
   187→}
   188→
   189→// size gives the number of unique watchers in the group.
   190→func (wg *watcherGroup) size() int { return len(wg.watchers) }
   191→
   192→// delete removes a watcher from the group.
   193→func (wg *watcherGroup) delete(wa *watcher) bool {
   194→	if _, ok := wg.watchers[wa]; !ok {
   195→		return false
   196→	}
   197→	wg.watchers.delete(wa)
   198→	if wa.end == nil {
   199→		wg.keyWatchers.delete(wa)
   200→		return true
   201→	}
   202→
   203→	ivl := adt.NewStringAffineInterval(string(wa.key), string(wa.end))
   204→	iv := wg.ranges.Find(ivl)
   205→	if iv == nil {
   206→		return false
   207→	}
   208→
   209→	ws := iv.Val.(watcherSet)
   210→	delete(ws, wa)
   211→	if len(ws) == 0 {
   212→		// remove interval missing watchers
   213→		if ok := wg.ranges.Delete(ivl); !ok {
   214→			panic("could not remove watcher from interval tree")
   215→		}
   216→	}
   217→
   218→	return true
   219→}
   220→
   221→// choose selects watchers from the watcher group to update
   222→func (wg *watcherGroup) choose(maxWatchers int, curRev, compactRev int64) (*watcherGroup, int64) {
   223→	if len(wg.watchers) < maxWatchers {
   224→		return wg, wg.chooseAll(curRev, compactRev)
   225→	}
   226→	ret := newWatcherGroup()
   227→	for w := range wg.watchers {
   228→		if maxWatchers <= 0 {
   229→			break
   230→		}
   231→		maxWatchers--
   232→		ret.add(w)
   233→	}
   234→	return &ret, ret.chooseAll(curRev, compactRev)
   235→}
   236→
   237→func (wg *watcherGroup) chooseAll(curRev, compactRev int64) int64 {
   238→	minRev := int64(math.MaxInt64)
   239→	for w := range wg.watchers {
   240→		if w.minRev > curRev {
   241→			// after network partition, possibly choosing future revision watcher from restore operation
   242→			// with watch key "proxy-namespace__lostleader" and revision "math.MaxInt64 - 2"
   243→			// do not panic when such watcher had been moved from "synced" watcher during restore operation
   244→			if !w.restore {
   245→				panic(fmt.Errorf("watcher minimum revision %d should not exceed current revision %d", w.minRev, curRev))
   246→			}
   247→
   248→			// mark 'restore' done, since it's chosen
   249→			w.restore = false
   250→		}
   251→		if w.minRev < compactRev {
   252→			select {
   253→			case w.ch <- WatchResponse{WatchID: w.id, CompactRevision: compactRev}:
   254→				w.compacted = true
   255→				wg.delete(w)
   256→			default:
   257→				// retry next time
   258→			}
   259→			continue
   260→		}
   261→		if minRev > w.minRev {
   262→			minRev = w.minRev
   263→		}
   264→	}
   265→	return minRev
   266→}
   267→
   268→// watcherSetByKey gets the set of watchers that receive events on the given key.
   269→func (wg *watcherGroup) watcherSetByKey(key string) watcherSet {
   270→	wkeys := wg.keyWatchers[key]
   271→	wranges := wg.ranges.Stab(adt.NewStringAffinePoint(key))
   272→
   273→	// zero-copy cases
   274→	switch {
   275→	case len(wranges) == 0:
   276→		// no need to merge ranges or copy; reuse single-key set
   277→		return wkeys
   278→	case len(wranges) == 0 && len(wkeys) == 0:
   279→		return nil
   280→	case len(wranges) == 1 && len(wkeys) == 0:
   281→		return wranges[0].Val.(watcherSet)
   282→	}
   283→
   284→	// copy case
   285→	ret := make(watcherSet)
   286→	ret.union(wg.keyWatchers[key])
   287→	for _, item := range wranges {
   288→		ret.union(item.Val.(watcherSet))
   289→	}
   290→	return ret
   291→}
